def parsing_nodes(string):
    # print(string)
    # 无[]
    if '[' not in string:
        return  string.split(',')
#         strings = [i.replace('SH-IDC','').replace('-','.') for i in string]
#         return strings
    # 存在多节点 跨ip段
    elif ',SH' in string:
        # 拆成N段
        strings = [ i  if i.startswith('SH') else 'SH'+i for i in string.split(',SH')]
        return_strings = []
        for string in strings:
            return_strings.extend(parsing_nodes(string))
        return return_strings
    else:
        prefix,endpoint = string.split('[')
        endpoint  =endpoint.strip(']').split(',')
        return_strings =[]
        for i in endpoint:
            if '-' not in i:
                return_strings.append(prefix+i)
            else:
                start,end = i.split('-')
                for i in range(int(start),int(end)+1):
                    return_strings.append(prefix+str(i))
        return return_strings

