                "node_used" :0,
                "tasks": []
            }
        if 'consum' in info[2] and user_name=="heyinan":
            pass
        else:
            vp_task[task_type]["node_used"] += gpu_all
            vp_task[task_type]["tasks"].append({
                "jobid": info[0],
                "user": user_name,
                "gpu": gpu_all,
                "node": info[-1]
            })
        for i in nodes:
            if i not in node_info:
                node_info[i] = {"gpu_used":0,"job_id":[],"users":{},"gpu_consume":0}
