def collect_vp_task(quota_vp, vp_task):
    exceeding_tasks = {}
    for vp, info in vp_task.items():
        node_used = info['node_used']
        quota = quota_vp.get(vp, 0)
        if node_used > quota:
            exceed_count = node_used - quota
            tasks = sorted(info['tasks'], key=lambda x: x['jobid'], reverse=True)
            total_gpu = 0
            exceeding = []
            for task in tasks:
                if total_gpu < exceed_count:
                    total_gpu += task['gpu']
                    exceeding.append(task)
                if total_gpu >= exceed_count:
                    break
            # 收集超限任务
            exceeding_tasks[vp] = {
                'exceed_count': exceed_count,
                'exceeding_tasks': exceeding
            }
    return exceeding_tasks
